// // This module converts a 4-bit binary input to its corresponding 4-bit Gray code output. The conversion occurs on the falling edge of the clock signal, and the module ensures that the Gray code output only updates when there is a change in the binary input. The least significant bit of the Gray code mirrors the least significant bit of the binary input, while each subsequent bit is generated by XORing adjacent bits of the binary input.
module top_module(
  input clk,
  input [3:0] bin,
  output reg [3:0] gray
);reg [3:0] prev_bin;

always @(posedge clk) begin
  if (bin !== prev_bin) begin
    gray[3] = bin[3];
    gray[2] = bin[3] ^ bin[2];
    gray[1] = bin[2] ^ bin[1];
    gray[0] = bin[1] ^ bin[0];
    prev_bin <= bin;
  end
end

endmodule
